package com.aadil.jobtracker.security;import com.aadil.jobtracker.responses.APIResponse;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/api/auth")public class AuthenticationController {    private final AuthenticationService authenticationService;    public AuthenticationController(AuthenticationService authenticationService) {        this.authenticationService = authenticationService;    }    @PostMapping("/register")    public ResponseEntity<APIResponse<Object>> registration (@RequestBody RequestRegisterDTO dto){        authenticationService.register(dto);        return ResponseEntity.ok(new APIResponse<>(true,null,"User Register Successfully"));    }    @PostMapping("/login")    public ResponseEntity<APIResponse<Object>> login(@RequestBody LoginRequestDTO dto){        authenticationService.login(dto);        return ResponseEntity.ok(new APIResponse<>(true,null,"User Login Successfully"));    }    @GetMapping("/test")    public String test(){        System.out.println("TEST HIT");        return "OK";    }}